func arrayToList(_ arr: [Int]) -> ListNode? {
    let dummy = ListNode(0)
    var curr = dummy
    for val in arr {
        curr.next = ListNode(val)
        curr = curr.next!
    }
    return dummy.next
}

func listToArray(_ head: ListNode?) -> [Int] {
    var res = [Int]()
    var curr = head
    while curr != nil {
        res.append(curr!.val)
        curr = curr!.next
    }
    return res
}

